        );
    }

    // --- BenchmarkSuite::load tests ---

    #[test]
    fn test_suite_load_empty_directory() {
        let tmp = tempdir().unwrap();
        let forge_dir = tmp.path().join(".forge");
        fs::create_dir_all(forge_dir.join("autoresearch/benchmarks/security")).unwrap();

